import { useState, useEffect } from "react";
import { getAllStocks, getMarketOverview } from "../services/stockService";
import StockCard from "../components/StockCard";
import SearchBar from "../components/SearchBar";

export default function Markets() {
  const [stocks, setStocks] = useState([]);
  const [marketOverview, setMarketOverview] = useState(null);
  const [loading, setLoading] = useState(true);
  const [watchlist, setWatchlist] = useState([]);
  const [filter, setFilter] = useState("all"); // all, gainers, losers
  const [sector, setSector] = useState("all");

  useEffect(() => {
    // Load watchlist from localStorage
    const savedWatchlist = localStorage.getItem("watchlist");
    if (savedWatchlist) {
      setWatchlist(JSON.parse(savedWatchlist));
    }

    fetchData();
    
    // Auto-refresh every 30 seconds
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, []);

  const fetchData = async () => {
    try {
      const [stocksData, overviewData] = await Promise.all([
        getAllStocks(),
        getMarketOverview()
      ]);
      setStocks(stocksData);
      setMarketOverview(overviewData);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setLoading(false);
    }
  };

  const toggleWatchlist = (stock) => {
    const newWatchlist = watchlist.includes(stock.symbol)
      ? watchlist.filter(s => s !== stock.symbol)
      : [...watchlist, stock.symbol];
    
    setWatchlist(newWatchlist);
    localStorage.setItem("watchlist", JSON.stringify(newWatchlist));
  };

  const filteredStocks = stocks.filter(stock => {
    if (filter === "gainers") return stock.change > 0;
    if (filter === "losers") return stock.change < 0;
    return true;
  }).filter(stock => {
    if (sector === "all") return true;
    return stock.sector === sector;
  });

  const sectors = ["all", ...new Set(stocks.map(s => s.sector))];

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading market data...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        {/* Market Overview */}
        {marketOverview && (
          <div className="mb-8">
            <h1 className="text-3xl font-bold text-gray-800 mb-6">Markets</h1>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
              <div className="bg-white rounded-lg shadow-md p-6">
                <div className="flex justify-between items-center">
                  <div>
                    <p className="text-sm text-gray-600 mb-1">SENSEX</p>
                    <p className="text-2xl font-bold text-gray-800">
                      {marketOverview.sensex.value.toLocaleString('en-IN')}
                    </p>
                  </div>
                  <div className={`text-right ${marketOverview.sensex.change >= 0 ? "text-green-600" : "text-red-600"}`}>
                    <p className="font-semibold">
                      {marketOverview.sensex.change >= 0 ? "+" : ""}
                      {marketOverview.sensex.change.toFixed(2)}
                    </p>
                    <p className="text-sm">
                      ({marketOverview.sensex.change >= 0 ? "+" : ""}
                      {marketOverview.sensex.changePercent.toFixed(2)}%)
                    </p>
                  </div>
                </div>
              </div>
              
              <div className="bg-white rounded-lg shadow-md p-6">
                <div className="flex justify-between items-center">
                  <div>
                    <p className="text-sm text-gray-600 mb-1">NIFTY 50</p>
                    <p className="text-2xl font-bold text-gray-800">
                      {marketOverview.nifty.value.toLocaleString('en-IN')}
                    </p>
                  </div>
                  <div className={`text-right ${marketOverview.nifty.change >= 0 ? "text-green-600" : "text-red-600"}`}>
                    <p className="font-semibold">
                      {marketOverview.nifty.change >= 0 ? "+" : ""}
                      {marketOverview.nifty.change.toFixed(2)}
                    </p>
                    <p className="text-sm">
                      ({marketOverview.nifty.change >= 0 ? "+" : ""}
                      {marketOverview.nifty.changePercent.toFixed(2)}%)
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Search and Filters */}
        <div className="mb-6">
          <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
            <div className="w-full md:w-96">
              <SearchBar />
            </div>
            
            <div className="flex gap-4">
              <select
                value={filter}
                onChange={(e) => setFilter(e.target.value)}
                className="px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
              >
                <option value="all">All Stocks</option>
                <option value="gainers">Top Gainers</option>
                <option value="losers">Top Losers</option>
              </select>
              
              <select
                value={sector}
                onChange={(e) => setSector(e.target.value)}
                className="px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
              >
                {sectors.map(s => (
                  <option key={s} value={s}>
                    {s === "all" ? "All Sectors" : s}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Stocks Grid */}
        <div className="mb-4 flex justify-between items-center">
          <h2 className="text-xl font-bold text-gray-800">
            {filter === "all" ? "All Stocks" : filter === "gainers" ? "Top Gainers" : "Top Losers"}
            <span className="text-sm font-normal text-gray-600 ml-2">
              ({filteredStocks.length} stocks)
            </span>
          </h2>
          <p className="text-sm text-gray-500">
            Auto-refreshes every 30 seconds
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {filteredStocks.map(stock => (
            <StockCard
              key={stock.symbol}
              stock={stock}
              onToggleWatchlist={toggleWatchlist}
              isInWatchlist={watchlist.includes(stock.symbol)}
            />
          ))}
        </div>

        {filteredStocks.length === 0 && (
          <div className="text-center py-12">
            <p className="text-gray-500">No stocks found matching your criteria.</p>
          </div>
        )}
      </div>
    </div>
  );
}
